-- Create test patient user
INSERT INTO users (openId, name, email, role, createdAt, updatedAt, lastSignedIn)
VALUES ('test-patient-001', 'John Patient', 'john.patient@test.com', 'user', NOW(), NOW(), NOW())
ON DUPLICATE KEY UPDATE name = 'John Patient';

-- Get patient user ID
SET @patientUserId = (SELECT id FROM users WHERE email = 'john.patient@test.com' LIMIT 1);

-- Create patient record (generate unique MRN)
INSERT INTO patients (mrn, firstName, lastName, dateOfBirth, gender, phone, email, address, status, createdAt, updatedAt)
VALUES (CONCAT('MRN', LPAD(@patientUserId, 8, '0')), 'John', 'Patient', '1980-05-15', 'male', '555-0123', 'john.patient@test.com', '123 Test St, Test City, TC 12345', 'active', NOW(), NOW())
ON DUPLICATE KEY UPDATE firstName = 'John';

-- Get patient ID and physician ID
SET @patientId = (SELECT id FROM patients WHERE email = 'john.patient@test.com' LIMIT 1);
SET @physicianId = (SELECT id FROM users WHERE role = 'admin' LIMIT 1);

SELECT @patientUserId AS patient_user_id, @patientId AS patient_id, @physicianId AS physician_id;

